function solve(n: number, edges: number[][]): number {
    // Build the graph
    const graph: Map<number, [number, number, number][]> = new Map();
    for (const [u, v, start, end] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u)!.push([v, start, end]);
    }

    // Priority queue: (time, node)
    const pq: [number, number][] = [(0, 0)];
    // Track the earliest time we reach each node
    const earliestTime: number[] = new Array(n).fill(-1);
    earliestTime[0] = 0;

    while (pq.length > 0) {
        let [time, node] = pq.shift()!;

        // If we have already reached this node with an earlier time, skip
        if (time > earliestTime[node]) {
            continue;
        }

        // If we have reached the destination, return the time
        if (node === n - 1) {
            return time;
        }

        // Try to move along each outgoing edge
        for (const [neighbor, start, end] of graph.get(node)!) {
            // Check if we can use this edge at the current time
            if (start <= time && time <= end) {
                const newTime = time + 1;
                if (earliestTime[neighbor] === -1 || newTime < earliestTime[neighbor]) {
                    earliestTime[neighbor] = newTime;
                    pq.push([newTime, neighbor]);
