                // Wait until the edge is available
                const waitTime = Math.max(start, time + 1) - time;
                const newTime = time + waitTime;
                if (earliestTime[neighbor] === -1 || newTime < earliestTime[neighbor]) {
                    earliestTime[neighbor] = newTime;
                    pq.push([newTime, neighbor]);
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}
